import java.sql.Connection;
import java.sql.DriverManager;
import java.sql.PreparedStatement;
import java.sql.ResultSet;
import java.sql.SQLException;
import java.util.concurrent.locks.ReentrantLock;

public class BankAccount {
    private int id;
    private double balance;
    private final ReentrantLock lock = new ReentrantLock();

    public BankAccount(int id, double initialBalance) {
        this.id = id;
        this.balance = initialBalance;
    }

    public void deposit(double amount, Runnable onSuccess, Runnable onFailure) throws SQLException, InterruptedException {
        lock.lock();
        try {
            if (balance + amount < 0) {
                onFailure.run();
                return;
            }
            balance += amount;
            updateBalance(id, balance);
            onSuccess.run();
        } finally {
            lock.unlock();
        }
    }

    public void withdraw(double amount, Runnable onSuccess, Runnable onFailure) throws SQLException, InterruptedException {
        lock.lock();
        try {
            if (balance - amount < 0) {
                onFailure.run();
                return;
            }
            balance -= amount;
            updateBalance(id, balance);
            onSuccess.run();
        } finally {
            lock.unlock();
        }
    }

    private void updateBalance(int id, double balance) throws SQLException {
        String url = "jdbc:mysql://localhost:3306/bank";
        String user = "username";
        String password = "password";
        Connection connection = DriverManager.getConnection(url, user, password);
        PreparedStatement statement = connection.prepareStatement("UPDATE accounts SET balance = ? WHERE id = ?");
        statement.setDouble(1, balance);
        statement.setInt(2, id);
        statement.executeUpdate();
        statement.close();
        connection.close();
    }
}